// // This module decodes two inputs into a 4-bit output using a multiplexer. If both inputs are high, it outputs 0100; if only the first input is high, it outputs 0001; if only the second input is high, it outputs 1001; and if both are low, it outputs 0101.
module top_module(
    input c,
    input d,
    output [3:0] mux_in
);assign mux_in = (c&d)?4'b1001:(c)?4'b0101:(d)?4'b0001:4'b0100;
endmodule
